const getTemplate = () => {
  return document
    .getElementById("card-template")
    .content.querySelector(".card")
    .cloneNode(true);
};

export const createCardElement = (
  data,
  { onPreviewPicture, onLikeIcon, onDeleteCard, onInfoClick, userId }
) => {
  const cardElement = getTemplate();
  const likeButton = cardElement.querySelector(".card__like-button");
  const deleteButton = cardElement.querySelector(".card__control-button_type_delete");
  const infoButton = cardElement.querySelector(".card__control-button_type_info");
  const cardImage = cardElement.querySelector(".card__image");
  const likeCount = cardElement.querySelector(".card__like-count");

  cardImage.src = data.link;
  cardImage.alt = data.name;
  cardElement.querySelector(".card__title").textContent = data.name;

  // Скрываем кнопку удаления, если пользователь не автор карточки
  if (data.owner._id !== userId) {
    deleteButton.remove();
  }

  // Устанавливаем начальное состояние лайка и количества лайков
  const isLiked = data.likes.some((user) => user._id === userId);
  if (isLiked) likeButton.classList.add("card__like-button_is-active");
  if (likeCount) likeCount.textContent = data.likes.length;

  // Передаём в колбэки карточный элемент и данные, чтобы внешняя логика
  // вызывала методы для локальных изменений разметки
  if (onLikeIcon) {
    likeButton.addEventListener("click", () => onLikeIcon(data, cardElement));
  }

  if (onDeleteCard) {
    deleteButton.addEventListener("click", () => onDeleteCard(cardElement, data));
  }

  if (onInfoClick && infoButton) {
    infoButton.addEventListener("click", () => onInfoClick(data._id));
  }

  if (onPreviewPicture) {
    cardImage.addEventListener("click", () => onPreviewPicture({ name: data.name, link: data.link }));
  }

  return cardElement;
};

export const updateCardLikes = (cardElement, updatedCard, currentUserId) => {
  if (!cardElement || !updatedCard) return;
  const likeButton = cardElement.querySelector(".card__like-button");
  const likeCount = cardElement.querySelector(".card__like-count");

  const isLiked = updatedCard.likes.some((user) => user._id === currentUserId);
  if (likeButton) {
    if (isLiked) likeButton.classList.add("card__like-button_is-active");
    else likeButton.classList.remove("card__like-button_is-active");
  }

  if (likeCount) {
    likeCount.textContent = updatedCard.likes.length;
  }
};

export const removeCardElement = (cardElement) => {
  if (!cardElement) return;
  cardElement.remove();
};
